import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Dropdown, Container } from 'react-bootstrap'; 
// Importaciones de Contextos
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import SearchBox from './SearchBox';
import HeaderSkeleton from './HeaderSkeleton'; 
import styles from './Header.module.css'; // Importamos el CSS Module

const Header = () => {
  const navigate = useNavigate();
  // Renombramos loading para evitar conflictos
  const { userInfo: user, logout, loading: authLoading } = useContext(AuthContext); 
  const { cartItems, isItemJustAdded } = useContext(CartContext);
  const { settings, loading: settingsLoading } = useContext(SettingsContext);

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const logoutHandler = () => {
    logout();
    navigate('/login');
  };

  // Cálculo de artículos totales para el badge del carrito
  const totalCartItems = cartItems.reduce((acc, item) => acc + item.qty, 0); 
  // Verificar si el usuario tiene permiso para el panel de administración
  const canAccessAdminPanel = user?.permissions?.includes('access:admin_panel');

  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // Clases base para enlaces de navegación (usamos el navLink del CSS Module)
  const navLinkClasses = styles.navLink;
  
  // Dividir el nombre del sitio para aplicar el acento en la última A (si existe)
  const siteName = settings?.siteName || 'TEasdasd';
  const lastAIndex = siteName.lastIndexOf('Á'); // Encontrar la última 'A' con acento
  
  // Construir el nombre, inyectando un <span> con la clase 'accent' para la A
  const accentedName = lastAIndex !== -1 
    ? siteName.substring(0, lastAIndex) + `<span class="${styles.accent}">Á</span>` + siteName.substring(lastAIndex + 1)
    : siteName;
  
  return (
    // Aplicamos la clase base del CSS Module
    <header 
      className={`w-full sticky top-0 z-50 transition-all duration-300 shadow-md ${styles.header}`}
    >
      {/* CRÍTICO: Quitamos el padding vertical (py-3) para que el CSS Module controle la altura */}
      <Container> 
        {/* CRÍTICO: d-flex para la alineación horizontal de Logo, Search y Acciones */}
        <div className="d-flex justify-content-between align-items-center h-full"> 
          
          {/* 1. Logo / Nombre del Sitio (Aplicamos la clase CSS Module) */}
          <Link 
            to="/" 
            // CRÍTICO: Solo usamos la clase del CSS Module. Eliminamos todo el Tailwind.
            className={`${styles.logoText} d-flex align-items-center gap-2 flex-shrink-0`} 
          > 
            {/* Imagen del Logo: Usamos la ruta estándar de la carpeta public */}
            <img 
                src={`${process.env.PUBLIC_URL}/images/logo.png`} // RUTA ASUMIDA EN PUBLIC/IMAGES/
                alt={settings?.siteName || 'Tecnotitlán Logo'} 
                // CRÍTICO: Usamos la clase del CSS Module para el tamaño de la imagen (80px)
                className={styles.logoImage} 
                // Si la imagen falla (404), ocultamos la imagen
                onError={(e) => { e.target.style.display = 'none'; }}
            />
            
            {/* Contenedor del Texto (stack vertical) */}
            <div className="flex flex-col items-start">
                <span dangerouslySetInnerHTML={{ __html: accentedName }}>
                  {/* Se renderiza el HTML inyectado para el acento */}
                </span>
            </div>
          </Link>

          {/* 2. Barra de búsqueda (Centrada, solo Desktop) */}
          {/* CRÍTICO: w-1/2 max-w-lg mx-auto para centrar y ocupar el espacio restante */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            <SearchBox /> 
          </div>

          {/* 3. Navegación Derecha (Carrito y Usuario) */}
          {/* w-auto flex-shrink-0 asegura que no se encoja */}
          <nav className="d-flex align-items-center gap-4 w-auto flex-shrink-0">
            {/* Icono del Carrito */}
            <Link 
              to="/cart" 
              className={`relative ${navLinkClasses} ${isItemJustAdded ? 'animate-pulse' : ''}`}
              style={{ color: isItemJustAdded ? 'var(--cta-color)' : '' }} 
            >
              <i className="fas fa-shopping-cart text-xl"></i>
              <span className="d-none d-md-inline ms-2 font-medium">Carrito</span>
              {totalCartItems > 0 && (
                <span className="absolute -top-2 -right-2 bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full shadow-sm">
                  {totalCartItems}
                </span>
              )}
            </Link>

            {/* Menú de Usuario/Login */}
            {user ? (
              <Dropdown align="end">
                <Dropdown.Toggle 
                  as="a" 
                  className={`${navLinkClasses} font-medium gap-2 cursor-pointer no-underline`} 
                >
                  {/* Avatar simple */}
                  <div className="w-8 h-8 rounded-full bg-gray-800 flex items-center justify-center border border-gray-700">
                    <i className="fas fa-user text-sm"></i>
                  </div>
                  <span className="d-none d-md-inline">{user.name || 'Super Administrador'}</span>
                </Dropdown.Toggle>

                <Dropdown.Menu className="shadow-xl border-0 rounded-lg mt-2 p-1 bg-white">
                  <Dropdown.Item as={Link} to="/profile" className="rounded py-2">Perfil</Dropdown.Item>
                  {canAccessAdminPanel && (
                    <Dropdown.Item as={Link} to="/admin/dashboard" className="rounded py-2">Panel Admin</Dropdown.Item>
                  )}
                  <Dropdown.Divider className="my-1" />
                  <Dropdown.Item onClick={logoutHandler} className="text-red-600 rounded py-2">Cerrar Sesión</Dropdown.Item>
                </Dropdown.Menu>
              </Dropdown>
            ) : (
              <Link to="/login" className={`${navLinkClasses} font-medium gap-2`}>
                <i className="fas fa-user"></i> <span className="d-none d-md-inline">Entrar</span>
              </Link>
            )}
          </nav>
        </div>
        
        {/* Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
